#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, M; scanf("%d %d", &N, &M);
        long long *F = (long long*)malloc(N * sizeof(long long));
        long long *C = (long long*)malloc(M * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &F[i]);
        for (int i = 0; i < M; ++i) scanf("%lld", &C[i]);
        int i = 0, j = 0;
        int lastChannel = 0; // 0 = football, 1 = cricket (start with football)
        long long switches = 0;
        while (i < N || j < M) {
            if (i < N && (j == M || F[i] < C[j])) {
                if (lastChannel != 0) ++switches;
                lastChannel = 0;
                ++i;
            } else {
                if (lastChannel != 1) ++switches;
                lastChannel = 1;
                ++j;
            }
        }
        printf("%lld\n", switches);
        free(F);
        free(C);
    }
    return 0;
}

