import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        F = [int(next(it)) for _ in range(N)]
        C = [int(next(it)) for _ in range(M)]
        i = j = 0
        last = 0  # 0 = football, 1 = cricket (start with football)
        switches = 0
        while i < N or j < M:
            if i < N and (j == M or F[i] < C[j]):
                if last != 0:
                    switches += 1
                last = 0
                i += 1
            else:
                if last != 1:
                    switches += 1
                last = 1
                j += 1
        out.append(str(switches))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

